document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector("[data-print-form]");if(!e)return;const t=e.querySelector('input[type=file]'),n=e.querySelector(".file-list"),o=e.querySelector("[data-submit]");t&&n&&t.addEventListener("change",()=>{n.textContent=Array.from(t.files).map(e=>e.name).join(", ")||"No files selected"});e.addEventListener("submit",e=>{if(o){o.disabled=!0;o.textContent="Sending…"}});});